-- ===============================================
-- بذر بيانات الأذكار الموثقة (Hisn al-Muslim Authentic Seed)
-- ===============================================

INSERT INTO public.azkar (zekr_text, count, category, fadl, read_time) VALUES
-- أذكار الصباح والمساء
('أَصْبَحْنَا وَأَصْبَحَ الْمُلْكُ لِلَّهِ، وَالْحَمْدُ لِلَّهِ، لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ، رَبِّ أَسْأَلُكَ خَيْرَ مَا فِي هَذَا الْيَوْمِ وَخَيْرَ مَا بَعْدَهُ، وَأَعُوذُ بِكَ مِنْ شَرِّ مَا فِي هَذَا الْيَوْمِ وَشَرِّ مَا بَعْدَهُ، رَبِّ أَعُوذُ بِكَ مِنَ الْكَسَلِ وَسُوءِ الْكِبَرِ، رَبِّ أَعُوذُ بِكَ مِنْ عَذَابٍ فِي النَّارِ وَعَذَابٍ فِي الْقَبْرِ.', 1, 'أذكار الصباح والمساء', 'من قاله حين يصبح أُجير من الجن حتى يمسي ومن قاله حين يمسي أُجير منهم حتى يصبح.', 'رواه مسلم'),
('اللَّهُمَّ أَنْتَ رَبِّي لَا إِلَهَ إِلَّا أَنْتَ، خَلَقْتَنِي وَأَنَا عَبْدُكَ، وَأَنَا عَلَى عَهْدِكَ وَوَعْدِكَ مَا اسْتَطَعْتُ، أَعُوذُ بِكَ مِنْ شَرِّ مَا صَنَعْتُ، أَبُوءُ لَكَ بِنِعْمَتِكَ عَلَيَّ، وَأَبُوءُ لَكَ بِذَنْبِي فَاغْفِرْ لِي؛ فَإِنَّهُ لَا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ.', 1, 'أذكار الصباح والمساء', 'سيد الاستغفار، من قاله موقناً به حين يمسي فمات من ليلته دخل الجنة، وكذلك إذا أصبح.', 'رواه البخاري'),
('بِسْمِ اللَّهِ الَّذِي لَا يَضُرُّ مَعَ اسْمِهِ شَيْءٌ فِي الْأَرْضِ وَلَا فِي السَّمَاءِ وَهُوَ السَّمِيعُ الْعَلِيمُ.', 3, 'أذكار الصباح والمساء', 'من قالها ثلاثاً إذا أصبح وثلاثاً إذا أمسى لم يضره شيء.', 'رواه الترمذي'),
('سُبْحَانَ اللَّهِ وَبِحَمْدِهِ.', 100, 'أذكار الصباح والمساء', 'من قالها حين يصبح وحين يمسي مائة مرة لم يأت أحد يوم القيامة بأفضل مما جاء به إلا أحد قال مثل ما قال أو زاد عليه.', 'رواه مسلم'),

-- أذكار الصلاة
('أستغفر الله', 3, 'أذكار الصلاة', 'قال رسول الله صلى الله عليه وسلم: إذا انصرف من صلاته استغفر ثلاثاً.', 'رواه مسلم'),
('اللَّهُمَّ أَنْتَ السَّلَامُ وَمِنْكَ السَّلَامُ، تَبَارَكْتَ يَا ذَا الْجَلَالِ وَالْإِكْرَامِ.', 1, 'أذكار الصلاة', 'يتم قوله مباشرة بعد الاستغفار الثلاث.', 'رواه مسلم'),
('سُبْحَانَ اللَّهِ', 33, 'أذكار الصلاة', 'من سبح الله في دبر كل صلاة ثلاثاً وثلاثين، وحمد الله ثلاثاً وثلاثين، وكبر الله ثلاثاً وثلاثين، فتلك تسعة وتسعون...', 'رواه مسلم'),
('الْحَمْدُ لِلَّهِ', 33, 'أذكار الصلاة', 'تكملة المائة بعد الصلاة.', 'رواه مسلم'),
('اللَّهُ أَكْبَرُ', 33, 'أذكار الصلاة', 'تكملة المائة بعد الصلاة.', 'رواه مسلم'),

-- أذكار النوم
('بِاسْمِكَ رَبِّي وَضَعْتُ جَنْبِي، وَبِكَ أَرْفَعُهُ، فَإِنْ أَمْسَكْتَ نَفْسِي فَارْحَمْهَا، وَإِنْ أَرْسَلْتَهَا فَاحْفَظْهَا بِمَا تَحْفَظُ بِهِ عِبَادَكَ الصَّالِحِينَ.', 1, 'أذكار النوم والاستيقاظ', 'من قال ذلك في فراشه فوكل به ملك يحفظه.', 'متفق عليه'),
('اللَّهُمَّ قِنِي عَذَابَكَ يَوْمَ تَبْعَثُ عِبَادَكَ.', 3, 'أذكار النوم والاستيقاظ', 'كان النبي صلى الله عليه وسلم إذا أراد أن ينام وضع يده تحت خده ثم قال ذلك.', 'رواه أبو داود'),

-- أدعية عامة
('اللَّهُمَّ إِنِّي أَسْأَلُكَ الْعَفْوَ وَالْعَافِيَةَ فِي الدُّنْيَا وَالْآخِرَةِ.', 1, 'أدعية عامة', 'دعاء جامع لخيري الدنيا والآخرة.', 'رواه أبو داود'),
('يَا حَيُّ يَا قَيُّومُ بِرَحْمَتِكَ أَسْتَغِيثُ أَصْلِحْ لِي شَأْنِي كُلَّهُ وَلَا تَكِلْنِي إِلَى نَفْسِي طَرْفَةَ عَيْنٍ.', 1, 'أدعية عامة', 'كان من دعاء النبي صلى الله عليه وسلم.', 'رواه الحاكم')
ON CONFLICT DO NOTHING;
